'use client'
import { cn } from '@cascivo/core'
import type { HTMLAttributes, ReactNode } from 'react'
import styles from './empty-state.module.css'

export interface EmptyStateProps extends Omit<HTMLAttributes<HTMLDivElement>, 'title'> {
  icon?: ReactNode
  title: string
  description?: string
  action?: ReactNode
  size?: 'md' | 'lg'
}

export function EmptyState({
  icon,
  title,
  description,
  action,
  size = 'md',
  className,
  ...props
}: EmptyStateProps) {
  return (
    <div data-size={size} className={cn(styles['empty-state'], className)} {...props}>
      {icon && (
        <span className={styles['icon']} aria-hidden="true">
          {icon}
        </span>
      )}
      <h3 className={styles['title']}>{title}</h3>
      {description && <p className={styles['description']}>{description}</p>}
      {action && <div className={styles['action']}>{action}</div>}
    </div>
  )
}

@layer cascivo.component {
  .empty-state {
    display: flex;
    flex-direction: column;
    align-items: center;
    text-align: center;
    gap: var(--cascivo-space-2);
    padding: var(--cascivo-space-8);
    font-family: var(--cascivo-font-sans);
    color: var(--cascivo-color-text);

    &[data-size='lg'] {
      gap: var(--cascivo-space-3);
      padding: var(--cascivo-space-12);
    }
  }

  .icon {
    display: flex;
    flex-shrink: 0;
    align-items: center;
    justify-content: center;
    inline-size: 3rem;
    block-size: 3rem;
    margin-block-end: var(--cascivo-space-2);
    font-size: var(--cascivo-text-xl);
    line-height: 1;
    color: var(--cascivo-color-text-muted);
    background-color: var(--cascivo-color-bg-subtle);
    border-radius: var(--cascivo-radius-full);

    .empty-state[data-size='lg'] & {
      inline-size: 4rem;
      block-size: 4rem;
      font-size: var(--cascivo-text-2xl);
    }
  }

  .title {
    margin: 0;
    font-size: var(--cascivo-text-base);
    font-weight: var(--cascivo-font-semibold);
    line-height: var(--cascivo-leading-snug);

    .empty-state[data-size='lg'] & {
      font-size: var(--cascivo-text-lg);
    }
  }

  .description {
    margin: 0;
    max-inline-size: 40ch;
    font-size: var(--cascivo-text-sm);
    color: var(--cascivo-color-text-subtle);
    line-height: var(--cascivo-leading-normal);

    .empty-state[data-size='lg'] & {
      font-size: var(--cascivo-text-base);
    }
  }

  .action {
    margin-block-start: var(--cascivo-space-2);
  }
}
